int ply_term_id(const char *name) {
    int lo = 0, hi = 145;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        int cmp = strcmp(ply_term_names[mid].name, name);
        if (cmp == 0) return ply_term_names[mid].id;
        if (cmp < 0) lo = mid + 1; else hi = mid - 1;
    }
    return -1;
}

